using UnityEngine;
using Unity.MLAgents.Sensors;
using Unity.MLAgents;

public class CardGameAgent : Agent
{
    public int maxHealth; // 玩家的最大健康值
    public int maxMana;   // 玩家的最大法力值
    public int maxHandSize; // 玩家手牌的最大尺寸
    public int maxBoardSize; // 棋盘上随从的最大数量
    public int totalCardCount; // 牌库中总卡牌量
    public CardGameManager gameManager; // 负责游戏逻辑的管理器

    //其他变量和方法...

    public override void CollectObservations(VectorSensor sensor)
    {
        // 添加当前健康值的观察信息，标准化为0到1之间的值
        sensor.AddObservation((float)gameManager.PlayerHealth / maxHealth);

        // 添加当前法力值的观察信息，标准化为0到1之间的值
        sensor.AddObservation((float)gameManager.PlayerMana / maxMana);

        // 为手牌中的每张卡片添加观察信息
        foreach (var card in gameManager.PlayerHand)
        {
            // 假定不存在的卡片用-1表示
            sensor.AddObservation(card != null ? card.CardId : -1);
        }

        // 如果手牌不足最大尺寸，用-1填充剩余的观察信息
        for (int i = gameManager.PlayerHand.Count; i < maxHandSize; i++)
        {
            sensor.AddObservation(-1);
        }

        // 添加场上随从的状态
        foreach (var minion in gameManager.PlayerBoard)
        {
            sensor.AddObservation(minion != null ? minion.CardId : -1);
            sensor.AddObservation(minion != null ? (float)minion.Health / minion.MaxHealth : 0f);
            sensor.AddObservation(minion != null ? (float)minion.Attack / minion.MaxAttack : 0f);
        }

        // 如果场上随从不足最大数量，用-1和0填充剩余的观察信息
        for (int i = gameManager.PlayerBoard.Count; i < maxBoardSize; i++)
        {
            sensor.AddObservation(-1); // 卡牌ID
            sensor.AddObservation(0f); // 健康值
            sensor.AddObservation(0f); // 攻击力
        }

        // 同样地，添加敌方棋盘状态
        // ...

        // 添加剩余牌库数量的观察信息，标准化为0到1之间的值
        sensor.AddObservation((float)gameManager.PlayerDeckCount / totalCardCount);
    }

    //其他函数...
}

